import { useState, useMemo, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "./css/Dashboard.css";

function VisitorDashboard() {
  const navigate = useNavigate();

  const [search, setSearch] = useState("");
  const [selectedType, setSelectedType] = useState("All");
  const [pets, setPets] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/api/items")
      .then((res) => res.json())
      .then((data) => setPets(data))
      .catch((err) => console.error("Failed to fetch pets:", err));
  }, []);

  const filteredPets = useMemo(() => {
    return pets.filter((pet) => {
      const matchesSearch =
        pet.name.toLowerCase().includes(search.toLowerCase()) ||
        pet.type.toLowerCase().includes(search.toLowerCase());

      const matchesType =
        selectedType === "All" || pet.type === selectedType;

      return matchesSearch && matchesType;
    });
  }, [pets, search, selectedType]);

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <h1>Meet Your Pet</h1>

        <div>
          <button
            className="logout-btn"
            onClick={() => navigate("/login")}
          >
            Login
          </button>

          <button
            className="logout-btn"
            style={{ marginLeft: "10px" }}
            onClick={() => navigate("/register")}
          >
            Register
          </button>
        </div>
      </div>

      <h2 className="pet-title">PET LISTING</h2>

      <div className="dashboard-layout">
        <div className="sidebar">
          <h3 className="sidebar-title">SEARCH</h3>

          <input
            className="search-input"
            type="text"
            placeholder="Search pets..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />

          <h3 className="sidebar-title">FILTER (TYPE)</h3>

          <select
            className="filter-select"
            value={selectedType}
            onChange={(e) => setSelectedType(e.target.value)}
          >
            <option value="All">All</option>
            <option value="Bird">Bird</option>
            <option value="Rabbit">Rabbit</option>
            <option value="Dog">Dog</option>
          </select>
        </div>

        <div className="pet-grid">
          {filteredPets.map((pet) => (
            <div className="pet-card" key={pet._id}>
              <img
                className="pet-image"
                src={pet.image}
                alt={pet.name}
              />
              <h3>{pet.name}</h3>
              <p className="pet-type">{pet.type}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default VisitorDashboard;
